import{bG as a,w as s,L as t,I as o,aT as l,aG as c}from"./chunks/framework.DGtQId0x.js";const g=JSON.parse('{"title":"","description":"","frontmatter":{"label":["金属元素化合物"],"level":null},"headers":[],"relativePath":"gaozhong/化学/题/1轮复习/04 金属元素化合物/27.md","filePath":"gaozhong/化学/题/1轮复习/04 金属元素化合物/27.md","lastUpdated":1734433524000}'),i={name:"gaozhong/化学/题/1轮复习/04 金属元素化合物/27.md"},n=o('<img src="https://my-course-public.oss-cn-shanghai.aliyuncs.com/xuexi/Snipaste_2024-12-12_16-26-35.png"><p>沉 Co 那里，加的是 NaHCO3。</p><details class="details custom-block"><summary>solution</summary><p>A 错。还有 BaSO4</p><p>B 错。三价Fe 一定存在。</p><p>C 对。图标错了，是 NaHCO3</p><p>因为溶液呈酸性，多余的碳酸根和 H+ 反应生成 CO2 和 H2O。</p></details><div class="tip custom-block"><p class="custom-block-title">TIP</p><ul><li>Fe,Co,Ni 是铁系元素，与 Fe 相似。FeSO4 不是沉淀，那么 CoSO4, NiSO4 也不是沉淀。</li><li>检验二价 Fe 用六氰合铁酸钾（Fe 是三价）。</li><li>要从溶液中得到固体、晶体，操作：蒸发浓缩、冷却结晶、过滤、洗涤、干燥。</li></ul></div>',4);function p(_,r,m,d,u,h){const e=l("ShowLabels");return c(),s("div",null,[t(e),n])}const C=a(i,[["render",p]]);export{g as __pageData,C as default};
